const data = $input.first().json;
const results = data.results || [];
const area = $('Called by Agent').first().json.area || $('Called by Agent').first().json.parameters?.area || 'unknown';

if (results.length === 0) {
  return [{ json: { pools: [], count: 0, area, status: 'no_results' } }];
}

const pools = results.slice(0, 15).map(p => ({
  name: p.name,
  address: p.formatted_address,
  rating: p.rating || null,
  reviews: p.user_ratings_total || 0,
  lat: p.geometry?.location?.lat,
  lng: p.geometry?.location?.lng,
  open_now: p.opening_hours?.open_now ?? null,
  place_id: p.place_id,
  price_level: p.price_level || null
}));

return [{ json: { pools, count: pools.length, area } }];

const poolData = $('Parse Pools').first().json;
try {
  const raw = $input.first().json.content[0].text;
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const rankings = JSON.parse(cleaned);
  return [{ json: {
    status: 'completed',
    workflow: '03_operations_pool_finder',
    area: poolData.area,
    pools_found: poolData.count,
    pools: poolData.pools,
    rankings,
    top_picks: rankings.filter(r => r.score >= 7),
    completedAt: new Date().toISOString()
  } }];
} catch (e) {
  return [{ json: {
    status: 'completed',
    workflow: '03_operations_pool_finder',
    area: poolData.area,
    pools_found: poolData.count,
    pools: poolData.pools,
    analysis_raw: $input.first().json.content?.[0]?.text || 'No analysis',
    completedAt: new Date().toISOString()
  } }];
}
